const raw = $json.choices[0].message.content;

// Strip markdown fences if model adds them despite instructions
const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('LLM did not return valid JSON. Raw output: ' + raw.substring(0, 300));
}

if (!parsed.items || !Array.isArray(parsed.items) || parsed.items.length === 0) {
  throw new Error('No items found in parsed receipt');
}

const executionId = $execution.id;
const receiptMeta = {
  receipt_id: executionId,
  store_name: parsed.store_name ?? null,
  store_branch: parsed.store_branch ?? null,
  store_address: parsed.store_address ?? null,
  store_postcode: parsed.store_postcode ?? null,
  receipt_date: parsed.receipt_date ?? null,
  receipt_time: parsed.receipt_time ?? null,
  currency: parsed.currency ?? 'GBP',
  subtotal: parsed.subtotal ?? null,
  discount_total: parsed.discount_total ?? null,
  tax_amount: parsed.tax_amount ?? null,
  total_amount: parsed.total_amount ?? null,
  payment_method: parsed.payment_method ?? null,
  last4_card_digits: parsed.last4_card_digits ?? null,
  loyalty_programme: parsed.loyalty_programme ?? null,
  source_image_url: $('Webhook').item.json.body.attachments[0].url,
  discord_user: $('Webhook').item.json.body.author.username,
  created_at: new Date().toISOString(),
};

// Return one n8n item per line item, with receipt metadata merged in
return parsed.items.map(item => ({
  json: {
    ...receiptMeta,
    line_number: item.line_number,
    product_name: item.product_name,
    normalised_name: item.normalised_name,
    category: item.category,
    quantity: item.quantity,
    unit: item.unit ?? null,
    unit_price: item.unit_price ?? null,
    line_total: item.line_total ?? null,
    is_discount_line: item.is_discount_line ?? false,
    discount_amount: item.discount_amount ?? null,
    is_taxable: item.is_taxable ?? false,
    tax_rate_percent: item.tax_rate_percent ?? 0,
    brand: item.brand ?? null,
    sku_or_barcode: item.sku_or_barcode ?? null,
  }
}));

